const crypto = require('crypto');
const webhookSecret = $env.STRIPE_WEBHOOK_SECRET;
const rawBody = $input.first().json.body;
const sigHeader = $input.first().json.headers['stripe-signature'];

// Verify Stripe webhook signature if secret is configured
if (webhookSecret && sigHeader) {
  const elements = sigHeader.split(',');
  const tsElement = elements.find(e => e.startsWith('t='));
  const sigElement = elements.find(e => e.startsWith('v1='));
  if (!tsElement || !sigElement) return [];
  const timestamp = tsElement.split('=')[1];
  const signature = sigElement.split('=')[1];
  const payload = timestamp + '.' + (typeof rawBody === 'string' ? rawBody : JSON.stringify(rawBody));
  const expected = crypto.createHmac('sha256', webhookSecret).update(payload).digest('hex');
  if (signature !== expected) {
    console.log('Invalid Stripe signature');
    return [];
  }
  const age = Math.floor(Date.now() / 1000) - parseInt(timestamp);
  if (age > 300) {
    console.log('Stripe event too old:', age, 'seconds');
    return [];
  }
}

const event = typeof rawBody === 'string' ? JSON.parse(rawBody) : $input.first().json;
if (event.type !== 'checkout.session.completed') {
  return [];
}

const session = event.data.object;
const priceId = session.line_items?.data?.[0]?.price?.id || session.metadata?.price_id || '';

// Map price IDs to ComfyUI packages
const packages = {
  'single':  { name: 'Foto Avulsa', photos: 1, delivery: '24h' },
  'pack10':  { name: 'Pacote 10 Fotos', photos: 10, delivery: '48h' },
  'monthly20': { name: 'Mensal 20 Fotos', photos: 20, delivery: 'ongoing' },
  'monthly50': { name: 'Mensal 50 Fotos', photos: 50, delivery: 'ongoing' }
};

const packageType = session.metadata?.package || 'single';
const pkg = packages[packageType] || packages.single;

return [{
  json: {
    email: session.customer_details?.email,
    name: session.customer_details?.name || 'Cliente',
    phone: session.customer_details?.phone || '',
    amount: session.amount_total / 100,
    currency: session.currency || 'brl',
    packageType,
    packageName: pkg.name,
    photos: pkg.photos,
    delivery: pkg.delivery,
    paymentId: session.id,
    timestamp: new Date().toISOString()
  }
}];

